const returnItems = [];
const items = $input.all();

// Loop through every file n8n found
for (let i = 0; i < items.length; i++) {
  const item = items[i];

  // 1. Get the filename
  const fileName = item.binary.data.fileName;

  // 2. Clean it up to create the account_id
  const accountId = fileName.replace('demo_', '').replace('.txt', '').trim();

  // 3. Extract the text content from the binary file 
  const binaryData = await this.helpers.getBinaryDataBuffer(i, 'data');
  const transcriptText = binaryData.toString('utf8');

  // 4. Push it to the JSON output for the next node (Groq)
  returnItems.push({
    json: {
      account_id: accountId,
      transcript: transcriptText
    }
  });
}

return returnItems;

