const returnItems = [];

for (const item of $input.all()) {
  // 1. Extract the text response from Groq
  const contentString = item.json.choices[0].message.content;

  // 2. Parse the text into a readable JSON object
  const parsedMemo = JSON.parse(contentString);

  // 3. Convert that object into a binary file for the Write node
  const buffer = Buffer.from(JSON.stringify(parsedMemo, null, 2));
  const binaryData = await this.helpers.prepareBinaryData(buffer, 'memo.json', 'application/json');

  // 4. Send the cleaned data and the binary file to the next node
  returnItems.push({
    json: {
      account_id: parsedMemo.account_id, // We extract this specifically for your folder path!
      full_response: parsedMemo
    },
    binary: {
      data: binaryData // This matches the "Input Binary Field" in your Write node
    }
  });
}

return returnItems;

const returnItems = [];
let i = 0; // We add a counter to track which file we are on

for (const item of $input.all()) {
  const contentString = item.json.choices[0].message.content;
  const parsedSpec = JSON.parse(contentString);

  const buffer = Buffer.from(JSON.stringify(parsedSpec, null, 2));
  const binaryData = await this.helpers.prepareBinaryData(buffer, 'agent_spec.json', 'application/json');

  // Here is the magic fix: We use [i] instead of .first() so it matches them up 1-to-1!
  // Note: Change 'Code' to the exact name of your first code node if it is different.
  const accountId = $('Code').all()[i].json.account_id || "ACC-UNKNOWN"; 

  returnItems.push({
    json: {
      account_id: accountId
    },
    binary: {
      data: binaryData
    }
  });

  i++; // Move to the next item
}

return returnItems;

const returnItems = [];

for (const item of $input.all()) {
  if (item.binary && item.binary.data) {
    // Grabs "onboarding_001_arctic_hvac.txt"
    const fileName = item.binary.data.fileName; 

    // Splits the name by '_'
    const parts = fileName.split('_'); 

    if (parts.length > 1) {
      // Grabs the "001" and makes "ACC-001"
      const accountId = "ACC-" + parts[1]; 

      returnItems.push({
        json: {
          account_id: accountId 
        },
        binary: {
          data: item.binary.data // Keeps the file attached!
        }
      });
    }
  }
}

return returnItems;

const items = $input.all();

for (let i = 0; i < items.length; i++) {
  if (items[i].binary && items[i].binary.data) {
    try {
      // 1. Safely ask n8n's backend to fetch the raw file buffer
      const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');

      // 2. Convert that safe buffer into readable text
      let jsonString = buffer.toString('utf-8');

      // 3. Clean up invisible characters (like BOM) and any AI markdown (```json)
      jsonString = jsonString.replace(/^\uFEFF/, ''); 
      jsonString = jsonString.replace(/```json/g, "").replace(/```/g, "").trim();

      // 4. Parse the completely clean string into a JSON object
      items[i].json.old_memo_json = JSON.parse(jsonString);

    } catch (error) {
      // If it still fails, this will output exactly what the text looked like so we can see what's breaking it!
      items[i].json.parse_error = error.message;
      items[i].json.failed_string = (await this.helpers.getBinaryDataBuffer(i, 'data')).toString('utf-8');
    }
  }
}

return items;

