const items = $input.all();

for (let i = 0; i < items.length; i++) {
  // 1. Grab the AI's updated JSON string
  const aiResponse = items[i].json.choices[0].message.content;

  // 2. Parse it and re-stringify it with 2 spaces so it looks pretty and readable
  const updatedMemo = JSON.parse(aiResponse);
  const formattedJson = JSON.stringify(updatedMemo, null, 2);

  // 3. Look back to your earlier code node to grab the correct Account ID for this specific file
  const accountId = $('Code in JavaScript2').all()[i].json.account_id; 

  // 4. Convert it into a binary file
  const buffer = Buffer.from(formattedJson, 'utf-8');

  // 5. Attach the new file to the output under the name 'data'
  items[i].binary = {
    data: await this.helpers.prepareBinaryData(buffer, accountId + '_memo_v2.json', 'application/json')
  };

  // Clean up the JSON output so the next node can easily read the ID
  items[i].json = { 
    account_id: accountId, 
    message: "V2 File Successfully Generated!" 
  };
}

return items;
